import React, { useState } from 'react';
import { findClients, generateOutreach } from '../services/aiService';

const skillOptions = [
  'React.js',
  'Node.js',
  'AWS',
  'GCP',
  'ML/AI',
  'Python',
  'DevOps',
  'MongoDB',
];

const ClientFinder = () => {
  const [skills, setSkills] = useState([]);
  const [clients, setClients] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [outreachLoading, setOutreachLoading] = useState(false);
  const [selectedClient, setSelectedClient] = useState(null);
  const [outreachDraft, setOutreachDraft] = useState(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  const toggleSkill = (skill) => {
    setError('');
    setSkills((current) =>
      current.includes(skill) ? current.filter((item) => item !== skill) : [...current, skill]
    );
  };

  const handleFindClients = async (event) => {
    event.preventDefault();
    if (skills.length === 0) {
      setError('Select at least one skill before searching.');
      return;
    }

    setLoading(true);
    setError('');
    setClients([]);
    setSuccessMessage('');

    const res = await findClients('', '', 'India', skills.join(', '));
    if (res.success) {
      setClients(Array.isArray(res.data) ? res.data : []);
      if (!Array.isArray(res.data)) {
        setError('AI returned an unexpected result format.');
      }
    } else {
      setError(res.error);
    }

    setLoading(false);
  };

  const handleGenerateOutreach = async (client) => {
    setOutreachLoading(true);
    setError('');
    setSuccessMessage('');

    try {
      const response = await generateOutreach(client, skills, 'Your Name');
      if (!response.success) {
        setError(response.error);
      } else {
        setSelectedClient(client);
        setOutreachDraft(response.outreach);
        setModalOpen(true);
      }
    } catch (requestError) {
      setError('Unable to generate outreach email right now.');
    }

    setOutreachLoading(false);
  };

  const handleCopy = async () => {
    if (outreachDraft) {
      await navigator.clipboard.writeText(`${outreachDraft.subject}\n\n${outreachDraft.body}`);
      setSuccessMessage('Email copied to clipboard!');
    }
  };

  const handleOpenGmail = () => {
    if (!outreachDraft) return;
    const subject = encodeURIComponent(outreachDraft.subject);
    const body = encodeURIComponent(outreachDraft.body);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  return (
    <div className="min-h-screen bg-slate-50 py-10">
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="rounded-[32px] border border-slate-200 bg-white p-8 shadow-sm">
          <div className="mb-8 flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.3em] text-slate-500">AI Client Finder</p>
              <h1 className="mt-3 text-3xl font-semibold text-slate-950">Find clients and auto-generate outreach</h1>
              <p className="mt-2 max-w-2xl text-sm text-slate-500">
                Select your skills, generate a list of ideal Indian clients, and create a tailored cold email for each profile.
              </p>
            </div>
            <button
              type="button"
              onClick={handleFindClients}
              disabled={loading}
              className="inline-flex h-14 items-center justify-center rounded-3xl bg-slate-950 px-6 text-sm font-semibold text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-400"
            >
              {loading ? 'Finding clients...' : 'Find Clients'}
            </button>
          </div>

          <div className="grid gap-4 lg:grid-cols-[1fr_320px]">
            <div className="space-y-4 rounded-[28px] border border-slate-200 bg-slate-50 p-6">
              <p className="text-sm font-semibold text-slate-700">Select your strongest skills</p>
              <div className="grid gap-3 sm:grid-cols-2">
                {skillOptions.map((skill) => (
                  <button
                    key={skill}
                    type="button"
                    onClick={() => toggleSkill(skill)}
                    className={`rounded-3xl border px-4 py-3 text-left text-sm transition ${
                      skills.includes(skill)
                        ? 'border-slate-950 bg-slate-950 text-white'
                        : 'border-slate-200 bg-white text-slate-700 hover:border-slate-400 hover:bg-slate-100'
                    }`}
                  >
                    {skill}
                  </button>
                ))}
              </div>
              <div className="rounded-3xl border border-slate-200 bg-white p-4 text-sm text-slate-600">
                Tip: Choose the technologies and services you want the AI to emphasize in outreach.
              </div>
            </div>

            <div className="rounded-[28px] border border-slate-200 bg-white p-6">
              <p className="text-sm font-semibold text-slate-700">Search settings</p>
              <div className="mt-4 rounded-3xl border border-slate-200 bg-slate-50 p-4 text-sm text-slate-600">
                Region is fixed to India for this feature, and skills are used to tailor the client list.
              </div>
              <div className="mt-6 text-sm text-slate-500">
                <p className="font-medium text-slate-700">Selected skills</p>
                <p className="mt-2">{skills.length > 0 ? skills.join(', ') : 'No skills selected yet.'}</p>
              </div>
            </div>
          </div>

          {error && (
            <div className="mt-6 rounded-3xl border border-rose-100 bg-rose-50 px-4 py-4 text-sm text-rose-700">
              {error}
            </div>
          )}

          {successMessage && (
            <div className="mt-6 rounded-3xl border border-emerald-100 bg-emerald-50 px-4 py-4 text-sm text-emerald-700">
              {successMessage}
            </div>
          )}
        </div>

        <div className="mt-8 grid gap-6 lg:grid-cols-2 xl:grid-cols-3">
          {clients.map((client, index) => (
            <div key={`${client.companyName}-${index}`} className="rounded-[32px] border border-slate-200 bg-white p-6 shadow-sm">
              <div className="mb-4 flex items-center justify-between gap-4">
                <div>
                  <p className="text-sm font-semibold text-slate-700">{client.companyName || client.company}</p>
                  <p className="mt-1 text-xs uppercase tracking-[0.2em] text-slate-400">{client.industry}</p>
                </div>
                <span className="rounded-full bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600">
                  {client.location}
                </span>
              </div>

              <div className="space-y-3 text-sm text-slate-600">
                <div>
                  <p className="font-medium text-slate-800">Decision maker</p>
                  <p>{client.decisionMaker}</p>
                </div>
                <div>
                  <p className="font-medium text-slate-800">Likely need</p>
                  <p>{client.likelyNeed}</p>
                </div>
                <div>
                  <p className="font-medium text-slate-800">Budget</p>
                  <p>{client.estimatedBudget}</p>
                </div>
              </div>

              <button
                type="button"
                onClick={() => handleGenerateOutreach(client)}
                disabled={outreachLoading}
                className="mt-6 inline-flex h-12 w-full items-center justify-center rounded-3xl bg-slate-950 text-sm font-semibold text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-300"
              >
                {outreachLoading ? 'Generating...' : 'Generate Outreach Email'}
              </button>
            </div>
          ))}

          {!loading && clients.length === 0 && (
            <div className="col-span-full rounded-[32px] border border-dashed border-slate-300 bg-white p-10 text-center text-slate-500">
              No client cards yet. Choose skills and click Find Clients to populate the board.
            </div>
          )}

          {loading && (
            <div className="col-span-full rounded-[32px] border border-slate-200 bg-white p-10 text-center text-slate-500">
              Searching for the best client opportunities…
            </div>
          )}
        </div>
      </div>

      {modalOpen && outreachDraft && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/70 px-4 py-6">
          <div className="w-full max-w-3xl overflow-hidden rounded-[32px] bg-white shadow-2xl">
            <div className="flex flex-col gap-4 border-b border-slate-200 px-6 py-5 sm:flex-row sm:items-center sm:justify-between">
              <div>
                <p className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-500">Outreach preview</p>
                <h2 className="mt-2 text-2xl font-semibold text-slate-950">{selectedClient?.companyName || selectedClient?.company}</h2>
              </div>
              <button
                type="button"
                onClick={() => setModalOpen(false)}
                className="inline-flex h-12 items-center justify-center rounded-3xl border border-slate-200 bg-slate-50 px-5 text-sm font-semibold text-slate-700 transition hover:bg-slate-100"
              >
                Close
              </button>
            </div>

            <div className="space-y-6 px-6 py-6">
              <div className="rounded-3xl border border-slate-200 bg-slate-50 p-6">
                <p className="text-sm font-semibold text-slate-500">Subject</p>
                <p className="mt-2 text-lg font-semibold text-slate-950">{outreachDraft.subject}</p>
              </div>
              <div className="rounded-3xl border border-slate-200 bg-slate-50 p-6">
                <p className="text-sm font-semibold text-slate-500">Email body</p>
                <div className="mt-3 whitespace-pre-wrap text-sm leading-7 text-slate-700">
                  {outreachDraft.body}
                </div>
              </div>
              <div className="flex flex-col gap-3 sm:flex-row sm:justify-end">
                <button
                  type="button"
                  onClick={handleCopy}
                  className="inline-flex h-12 items-center justify-center rounded-3xl bg-slate-950 px-6 text-sm font-semibold text-white transition hover:bg-slate-800"
                >
                  Copy Email
                </button>
                <button
                  type="button"
                  onClick={handleOpenGmail}
                  className="inline-flex h-12 items-center justify-center rounded-3xl border border-slate-200 bg-white px-6 text-sm font-semibold text-slate-950 transition hover:bg-slate-50"
                >
                  Open in Gmail
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ClientFinder;
